from __future__ import annotations

from dataclasses import dataclass
from decimal import Decimal
from typing import Protocol


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is empty or invalid."""


class InvalidUnitPriceError(ShoppingCartError):
    """Raised when a unit price is negative."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when a quantity is not positive."""


class ProductNotFoundError(ShoppingCartError):
    """Raised when a requested product is not in the cart."""


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount value is invalid."""


@dataclass(frozen=True, slots=True)
class CartItem:
    """Represents a single product entry in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def line_total(self) -> Decimal:
        """Return the total price for this item before discounts."""
        return self.unit_price * self.quantity


class Discount(Protocol):
    """Protocol for discount strategies."""

    def calculate(self, subtotal: Decimal) -> Decimal:
        """Return the discount amount for a given subtotal."""


@dataclass(frozen=True, slots=True)
class PercentageDiscount:
    """Percentage-based discount strategy."""

    percentage: Decimal

    def calculate(self, subtotal: Decimal) -> Decimal:
        """Return the percentage discount amount for a given subtotal."""
        return subtotal * (self.percentage / Decimal("100"))


@dataclass(frozen=True, slots=True)
class FlatDiscount:
    """Flat amount discount strategy."""

    amount: Decimal

    def calculate(self, subtotal: Decimal) -> Decimal:
        """Return the flat discount amount for a given subtotal."""
        return min(self.amount, subtotal)


class ShoppingCart:
    """Manage cart items, discounts, and total calculations."""

    def __init__(self) -> None:
        self._items: dict[str, CartItem] = {}
        self._discount: Discount | None = None

    def add_item(
        self,
        product_name: str,
        unit_price: Decimal | int | float | str,
        quantity: int = 1,
    ) -> None:
        """Add an item to the cart or increase its quantity if it already exists."""
        normalized_name = self._validate_product_name(product_name)
        normalized_price = self._validate_unit_price(unit_price)
        self._validate_quantity(quantity)

        if normalized_name in self._items:
            existing_item = self._items[normalized_name]
            self._items[normalized_name] = CartItem(
                product_name=existing_item.product_name,
                unit_price=normalized_price,
                quantity=existing_item.quantity + quantity,
            )
            return

        self._items[normalized_name] = CartItem(
            product_name=normalized_name,
            unit_price=normalized_price,
            quantity=quantity,
        )

    def remove_item(self, product_name: str) -> CartItem:
        """Remove an item from the cart by product name and return it."""
        normalized_name = self._validate_product_name(product_name)
        self._ensure_item_exists(normalized_name)
        return self._items.pop(normalized_name)

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing cart item."""
        normalized_name = self._validate_product_name(product_name)
        self._validate_quantity(quantity)
        existing_item = self._get_item(normalized_name)

        self._items[normalized_name] = CartItem(
            product_name=existing_item.product_name,
            unit_price=existing_item.unit_price,
            quantity=quantity,
        )

    def calculate_subtotal(self) -> Decimal:
        """Return the cart subtotal before discounts."""
        return sum(
            (cart_item.line_total for cart_item in self._items.values()),
            Decimal("0"),
        )

    def apply_percentage_discount(
        self,
        percentage: Decimal | int | float | str,
    ) -> None:
        """Apply a percentage discount to the cart."""
        normalized_percentage = self._to_decimal(percentage)

        if normalized_percentage < Decimal("0") or normalized_percentage > Decimal("100"):
            raise InvalidDiscountError(
                "Percentage discount must be between 0 and 100 inclusive."
            )

        self._discount = PercentageDiscount(normalized_percentage)

    def apply_flat_discount(self, amount: Decimal | int | float | str) -> None:
        """Apply a flat discount amount to the cart."""
        normalized_amount = self._to_decimal(amount)

        if normalized_amount < Decimal("0"):
