    def _validate_unit_price(unit_price: Decimal | int | float | str) -> Decimal:
        normalized_price = ShoppingCart._to_decimal(unit_price)

        if normalized_price < Decimal("0"):
            raise InvalidUnitPriceError("Unit price cannot be negative.")

